const r=Math.PI/180;function M(t,a,n,s){const c=(n-t)*r,o=(s-a)*r,i=Math.sin(c/2)**2+Math.cos(t*r)*Math.cos(n*r)*Math.sin(o/2)**2;return 6371e3*2*Math.atan2(Math.sqrt(i),Math.sqrt(1-i))}function f(t,a,n,s){const c=t*r,o=n*r,i=(s-a)*r,h=Math.sin(i)*Math.cos(o),u=Math.cos(c)*Math.sin(o)-Math.sin(c)*Math.cos(o)*Math.cos(i);return(Math.atan2(h,u)*(180/Math.PI)+360)%360}function e(t,a,n,s,c=1.5){const o=M(t,a,n,s),i=f(t,a,n,s)*r,h=o*Math.sin(i),u=-o*Math.cos(i);return[h,c,u]}function D(t){return t<1e3?`${Math.round(t)}m`:`${(t/1e3).toFixed(1)}km`}function l(t){return["N","NE","E","SE","S","SW","W","NW"][Math.round(t/45)%8]}function E(t){return t<50?1:t<200?1.5:t<500?2.5:t<1e3?3.5:5}function S([t,a,n],s=200){const c=Math.sqrt(t*t+n*n);if(c<=s)return[t,a,n];const o=s/c;return[t*o,a,n*o]}export{S as a,E as b,M as c,f as d,l as e,D as f,e as g};
